  1	import * as React from 'react';
  2	import {
  3	  getClusterName,
  4	  LastHeartBeat,
  5	} from '@odf/core/components/storage-consumers/client-list';
  6	import {
  7	  getName,
  8	  getUID,
  9	  StorageConsumerKind,
 10	  ClusterVersionModel,
 11	  ClusterVersionKind,
 12	} from '@odf/shared';
 13	import { useK8sGet } from '@odf/shared/hooks';
 14	import { TableSkeletonLoader } from '@odf/shared/skeletal-loader/TableSkeleton';
 15	import {
 16	  K8sResourceCommon,
 17	  ListPageFilter,
 18	  useListPageFilter,
 19	} from '@openshift-console/dynamic-plugin-sdk';
 20	import * as _ from 'lodash-es';
 21	import { Thead, Tr, Th, Tbody, Table, Td } from '@patternfly/react-table';
 22	import { isLocalClientCluster } from '../../utils';
 23	
 24	export type SelectedResources = string[];
 25	
 26	type ResourceDistributionTableProps = {
 27	  resources: StorageConsumerKind[];
 28	  selectedResources: string[];
 29	  setSelectedResources: React.Dispatch<React.SetStateAction<string[]>>;
 30	  RowGenerator?: React.FC<RowGeneratorProps<K8sResourceCommon>>;
 31	  columns: string[];
 32	  loaded: boolean;
 33	};
 34	
 35	type RowGeneratorProps<T extends K8sResourceCommon> = {
 36	  resource: T;
 37	  onSelect: (selected: boolean) => void;
 38	  isSelected: boolean;
 39	  localClusterId: string;
 40	  rowIndex: number;
 41	};
 42	
 43	const RowComponent: React.FC<RowGeneratorProps<StorageConsumerKind>> = ({
 44	  resource,
 45	  onSelect,
 46	  isSelected,
 47	  localClusterId,
 48	  rowIndex,
 49	}) => {
 50	  const name = getName(resource);
 51	  const clusterName = getClusterName(resource);
 52	  const isLocalClient = isLocalClientCluster(resource, localClusterId);
 53	  return (
 54	    <Tr key={getUID(resource)}>
 55	      <Td
 56	        select={{
 57	          rowIndex,
 58	          onSelect: (_event, isSelecting) => onSelect(isSelecting),
 59	          isSelected,
 60	          isDisabled: isLocalClient,
 61	        }}
 62	      />
 63	      <Td>{name}</Td>
 64	      <Td>{clusterName}</Td>
 65	      <Td>
 66	        <LastHeartBeat heartbeat={resource.status?.lastHeartbeat} />{' '}
 67	      </Td>
 68	    </Tr>
 69	  );
 70	};
 71	export const StorageConsumerTable: React.FC<ResourceDistributionTableProps> = ({
 72	  resources,
 73	  RowGenerator = RowComponent,
 74	  selectedResources,
 75	  setSelectedResources,
 76	  loaded,
 77	  columns,
 78	}) => {
 79	  const [cv, cvLoaded] = useK8sGet<ClusterVersionKind>(
 80	    ClusterVersionModel,
 81	    'version'
 82	  );
 83	  const localClusterId = cv?.spec?.clusterID;
 84	  const localConsumerUID = getUID(
 85	    resources?.find((resource) =>
 86	      isLocalClientCluster(resource, localClusterId)
 87	    )
 88	  );
 89	
 90	  const [areAllResourcesSelected, setAllResourcesSelected] =
 91	    React.useState(false);
 92	
 93	  React.useEffect(() => {
 94	    const allSelected = _.isEmpty(resources)
 95	      ? false
 96	      : resources.every((resource) => {
 97	          const uid = getUID(resource);
 98	          return selectedResources.includes(uid);
 99	        });
100	    if (allSelected) {
101	      setAllResourcesSelected(true);
102	    } else {
103	      setAllResourcesSelected(false);
104	    }
105	  }, [resources, selectedResources]);
106	
107	  const onSelectRow = React.useCallback(
108	    (resource: K8sResourceCommon) => (selected: boolean) => {
109	      const updatedResources = selected
110	        ? [...selectedResources, getUID(resource)]
111	        : selectedResources.filter((name) => name !== getUID(resource));
112	      setSelectedResources(updatedResources);
113	    },
114	    [selectedResources, setSelectedResources]
115	  );
116	
117	  const isRowSelected = React.useCallback(
118	    (resource: K8sResourceCommon) =>
119	      selectedResources.includes(getUID(resource)),
120	    [selectedResources]
121	  );
122	
123	  const [unfilteredData, filteredData, onFilterChange] =
124	    useListPageFilter(resources);
125	
126	  const selectAllResources = (select: boolean) => {
127	    const allUIDs = new Set(selectedResources);
128	    if (select) {
129	      filteredData?.forEach((resource) => {
130	        const uid = getUID(resource);
131	        if (uid !== localConsumerUID) allUIDs.add(uid);
132	      });
133	    } else {
134	      selectedResources?.forEach((resourceUID) => {
135	        if (resourceUID !== localConsumerUID) allUIDs.delete(resourceUID);
136	      });
137	    }
138	    setSelectedResources([...allUIDs]);
139	  };
140	  return !loaded || !cvLoaded ? (
141	    <TableSkeletonLoader columns={4} rows={8} />
142	  ) : (
143	    <>
144	      <ListPageFilter
145	        data={unfilteredData}
146	        loaded={loaded && cvLoaded}
147	        onFilterChange={onFilterChange}
148	        hideColumnManagement={true}
149	      />
150	      <Table variant="compact" data-test-id="resource-distribution-table">
151	        <Thead>
152	          <Tr>
153	            <Th
154	              select={{
155	                onSelect: (_event, isSelecting) =>
156	                  selectAllResources(isSelecting),
157	                isSelected: areAllResourcesSelected,
158	              }}
159	            />
160	            {columns.map((columnName) => (
161	              <Th key={columnName}>{columnName}</Th>
162	            ))}
163	          </Tr>
164	        </Thead>
165	        <Tbody>
166	          {filteredData.map((resource, index) => (
167	            <RowGenerator
168	              key={resource.metadata.uid}
169	              resource={resource}
170	              rowIndex={index}
171	              onSelect={onSelectRow(resource)}
172	              isSelected={isRowSelected(resource)}
173	              localClusterId={localClusterId}
174	            />
175	          ))}
176	        </Tbody>
177	      </Table>
178	    </>
179	  );
180	};

